$(document).ready(function(){obterBanner("6ac807e2-d6a0-47b4-97de-13409fbc6c08")});var obterBanner=function(publicacao){$.ajax({url:"https://api.unip.br/sistemas/banner/servico/publicado/"+publicacao,cache:!1,async:!1,success:function(resultado){var ativo='active';var haLink=!1;var localLg=null;var alturaLg=null;var larguraLg=null;var alvoLg=null;var htmlLg=null;var localXs=null;var alturaXs=null;var larguraXs=null;var alvoXs=null;var htmlXs=null;for(var i=0;i<resultado.length;i++){localLg=resultado[i].bannerLg.local;alturaLg=resultado[i].bannerLg.altura;larguraLg=resultado[i].bannerLg.largura;haLink=resultado[i].link!=null?!0:!1;alvoLg="#banners";if(resultado[i].bannerXs==null){localXs=localLg;alturaXs=alturaLg;larguraXs=larguraLg}else{localXs=resultado[i].bannerXs.local;alturaXs=resultado[i].bannerXs.altura;larguraXs=resultado[i].bannerXs.largura}
alvoXs="#mob-banners";if(resultado[i].status=="Ativo"){if(haLink){htmlLg="<div class='carousel-item "+ativo+"'><a href='"+resultado[i].link+"'><img class='d-none d-sm-none d-md-block w-100' src='"+localLg+"' alt='"+resultado[i].alt+"' title='"+resultado[i].alt+"'></a></div>";htmlXs="<div class='carousel-item "+ativo+"'><a href='"+resultado[i].link+"'><img class='d-block d-sm-block d-md-none w-100' src='"+localXs+"' alt='"+resultado[i].alt+"' title='"+resultado[i].alt+"'></a></div>";montarControles("#indicators","#carousel",i,ativo);montarControles("#mob-indicators","#mob-carousel",i,ativo)}else{htmlLg="<div class='carousel-item "+ativo+"'><img class='d-none d-sm-none d-md-block w-100' src='"+localLg+"' alt='"+resultado[i].alt+"' title='"+resultado[i].alt+"'></div>";htmlXs="<div class='carousel-item "+ativo+"'><img class='d-block d-sm-block d-md-none w-100' src='"+localXs+"' alt='"+resultado[i].alt+"' title='"+resultado[i].alt+"'></div>";montarControles("#indicators","#carousel",i,ativo);montarControles("#mob-indicators","#mob-carousel",i,ativo)}}
ativo="";$(alvoLg).append(htmlLg);$(alvoXs).append(htmlXs)}}})}
var montarControles=function(alvo,carousel,dataSlide,ativo){var content="<li data-target='"+carousel+"' data-slide-to='"+dataSlide+"' class='"+ativo+"'></li>";$(alvo).append(content)}